if (this.tok.type === tt.comma) {
  let node = this.startNodeAt(start)
  node.expressions = [expr]
  while (this.eat(tt.comma)) node.expressions.push(this.parseMaybeAssign(noIn))
  return this.finishNode(node, "SequenceExpression")
}

if (this.tok.type.isAssign) {
  let node = this.startNodeAt(start)
  node.operator = this.tok.value
  node.left = this.tok.type === tt.eq ? this.toAssignable(left) : this.checkLVal(left)
  this.next()
  node.right = this.parseMaybeAssign(noIn)
  return this.finishNode(node, "AssignmentExpression")
}

if (this.eat(tt.question)) {
  let node = this.startNodeAt(start)
  node.test = expr
  node.consequent = this.parseMaybeAssign()
  node.alternate = this.expect(tt.colon) ? this.parseMaybeAssign(noIn) : this.dummyIdent()
  return this.finishNode(node, "ConditionalExpression")
}

if (!sawUnary && this.eat(tt.starstar)) {
  let node = this.startNodeAt(start)
  node.operator = "**"
  node.left = expr
  node.right = this.parseMaybeUnary(false)
  return this.finishNode(node, "BinaryExpression")
}

if (this.options.ecmaVersion >= 6 && this.eat(tt.dot)) {
  node.meta = meta
  node.property = this.parseIdent(true)
  return this.finishNode(node, "MetaProperty")
}

if (this.tok.type === tt.parenL) {
  node.arguments = this.parseExprList(tt.parenR)
} else {
  node.arguments = []
}

if (node.expression) {
  node.body = this.parseMaybeAssign()
} else {
  node.body = this.parseBlock()
  this.toks.adaptDirectivePrologue(node.body.body)
}

do {
    let decl = this.startNode()
    decl.id = this.options.ecmaVersion >= 6 ? this.toAssignable(this.parseExprAtom(), true) : this.parseIdent()
    decl.init = this.eat(tt.eq) ? this.parseMaybeAssign(noIn) : null
    node.declarations.push(this.finishNode(decl, "VariableDeclarator"))
  } while (this.eat(tt.comma))

if (!node.declarations.length) {
  let decl = this.startNode()
  decl.id = this.dummyIdent()
  node.declarations.push(this.finishNode(decl, "VariableDeclarator"))
}

if (this.tok.type === tt.name) node.id = this.parseIdent()
  else if (isStatement === true) node.id = this.dummyIdent()
  else node.id = null

if (this.toks.type === tt.privateId) {
  element.computed = false
  element.key = this.parsePrivateIdent()
} else {
  this.parsePropertyName(element)
}

if (this.tok.start >= this.nextLineStart) {
  while (this.tok.start >= this.nextLineStart) {
    this.curLineStart = this.nextLineStart
    this.nextLineStart = this.lineEnd(this.curLineStart) + 1
  }
  this.curIndent = this.indentationAfter(this.curLineStart)
}

if (typeof test === "string")
    return type => type === test
  else if (!test)
    return () => true
  else
    return test

if (node.type === "Identifier")
    c(node, st, "VariablePattern")
  else if (node.type === "MemberExpression")
    c(node, st, "MemberPattern")
  else
    c(node, st)

for (let prop of node.properties) {
  if (prop.type === "Property") {
    if (prop.computed) c(prop.key, st, "Expression")
    c(prop.value, st, "Pattern")
  } else if (prop.type === "RestElement") {
    c(prop.argument, st, "Pattern")
  }
}

if (this.type === tt.comma) {
  let node = this.startNodeAt(startPos, startLoc)
  node.expressions = [expr]
  while (this.eat(tt.comma)) node.expressions.push(this.parseMaybeAssign(forInit, refDestructuringErrors))
  return this.finishNode(node, "SequenceExpression")
}

if (this.type === tt.parenL || this.type === tt.name) {
  this.potentialArrowAt = this.start
  this.potentialArrowInForAwait = forInit === "await"
}

if (!(expr.type === "ArrowFunctionExpression" && expr.start === startPos) && this.eat(tt.question)) {
  let node = this.startNodeAt(startPos, startLoc)
  node.test = expr
  node.consequent = this.parseMaybeAssign()
  this.expect(tt.colon)
  node.alternate = this.parseMaybeAssign(forInit)
  return this.finishNode(node, "ConditionalExpression")
}

if (!incDec && this.eat(tt.starstar)) {
  if (sawUnary)
    this.unexpected(this.lastTokStart)
  else
    return this.buildBinary(startPos, startLoc, expr, this.parseMaybeUnary(null, false, false, forInit), "**", false)
} else {
  return expr
}

while (!curElt.tail) {
  if (this.type === tt.eof) this.raise(this.pos, "Unterminated template literal")
  this.expect(tt.dollarBraceL)
  node.expressions.push(this.parseExpression())
  this.expect(tt.braceR)
  node.quasis.push(curElt = this.parseTemplateElement({isTagged}))
}

if (!isPattern && !containsEsc && this.options.ecmaVersion >= 8 && !isGenerator && this.isAsyncProp(prop)) {
  isAsync = true
  isGenerator = this.options.ecmaVersion >= 9 && this.eat(tt.star)
  this.parsePropertyName(prop)
} else {
  isAsync = false
}

if (re.test(name)) {
  if (!this.inAsync && name === "await")
    this.raiseRecoverable(start, "Cannot use keyword 'await' outside an async function")
  this.raiseRecoverable(start, `The keyword '${name}' is reserved`)
}

if (!liberal) {
  this.checkUnreserved(node)
  if (node.name === "await" && !this.awaitIdentPos)
    this.awaitIdentPos = node.start
}

if (this.options.checkPrivateFields) {
  if (this.privateNameStack.length === 0) {
    this.raise(node.start, `Private field '#${node.name}' must be declared in an enclosing class`)
  } else {
    this.privateNameStack[this.privateNameStack.length - 1].used.push(node)
  }
}

if (this.type === tt.semi || this.canInsertSemicolon() || (this.type !== tt.star && !this.type.startsExpr)) {
  node.delegate = false
  node.argument = null
} else {
  node.delegate = this.eat(tt.star)
  node.argument = this.parseMaybeAssign(forInit)
}

for (let i = 0; i < set.length; i += 2) {
  pos += set[i]
  if (pos > code) return false
  pos += set[i + 1]
  if (pos >= code) return true
}

export class SourceLocation {
  constructor(p, start, end) {
    this.start = start
    this.end = end
    if (p.sourceFile !== null) this.source = p.sourceFile
  }
}

for (let line = 1, cur = 0;;) {
  let nextBreak = nextLineBreak(input, cur, offset)
  if (nextBreak < 0) return new Position(line, offset - cur)
  ++line
  cur = nextBreak
}

for (let i = 0; i < end; i++) {
  let elt = exprList[i]
  if (elt) this.toAssignable(elt, isBinding)
}

if (end) {
  let last = exprList[end - 1]
  if (this.options.ecmaVersion === 6 && isBinding && last && last.type === "RestElement" && last.argument.type !== "Identifier")
    this.unexpected(last.argument.start)
}
